  requires a >= 0 && b >= 0 && c >= 0
  ensures IsAchievable(a, b, c, maxCandies)
  ensures IsOptimal(a, b, c, maxCandies)
{
  maxCandies := (a + b + c) / 2;

  // Achievability: split the largest pile, witness s equalizes both sides
  if a >= b && a >= c {
    // Split pile a; Alice takes b, Bob takes c
